// Definición de IDs de campos personalizados en ClickUp
const CUSTOM_FIELDS = {
  asistente: "f15f367f-fc1b-4bdc-ab52-b797a10ffb74",
  transcripcion: "c24a78eb-3a4a-4c5b-ad70-37d58070ea6b",
  preguntas_requeridas: "19cffd24-c5c4-493b-b292-ff7b170c6bc1",
  excesos_identificados: "e3cabf44-7e55-481c-b18e-017dd204622d",
  evaluacion_general: "c6c88fa7-46f8-42b2-a32d-bf9c596b2f8b",
  direccion_correcta: "1477d347-3a05-4a24-9b8f-489c583dec35", 
  puntuacion: "244f4bb5-8a0c-4aaa-9818-83a8b8c23922",
  areas_de_mejora: "ad1b6cfb-aeaf-4dee-bf84-c3bdd49ff006",
  puntos_debiles: "4d085d21-9949-42ff-a719-1ab7d4eba4d7"
};

// Función para sanitizar texto
function sanitizarTexto(texto) {
  if (texto === undefined || texto === null) return '';
  return String(texto)
    .replace(/\\/g, "\\\\")
    .replace(/"/g, "'")
    .replace(/\n/g, "\\n");
}


let preguntasRequeridas = '';
let excesosIdentificados = '';
let evaluacionGeneral = '';
let direccionCorrecta = '';
let puntuacion = '';
let areasDeMejora = '';
let puntosDebiles = '';

try {
  // Referencia correcta a las variables
  const inputData = $input.first().json;
  if (inputData && inputData.output) {
    preguntasRequeridas = inputData.output["Preguntas requeridas"] || '';
    direccionCorrecta = inputData.output["Dirección correcta"] || '';
    excesosIdentificados = inputData.output["Excesos identificados"] || '';
    evaluacionGeneral = inputData.output["Evaluación general"] || '';
    areasDeMejora = inputData.output["Areas de mejora"] || inputData.output["Áreas de mejora"] || '';
    puntosDebiles = inputData.output["Puntos debiles"] || inputData.output["Puntos débiles"] || '';
    // Intentar diferentes variantes del nombre del campo
    puntuacion = inputData.output["Puntuacion"] || 
                inputData.output["Puntuación"] || 
                inputData.output["PUNTUACION"] || 
                inputData.output["PUNTUACIÓN"] || '';
    console.log("Datos del AI Agent obtenidos correctamente");
    console.log("Puntuación obtenida:", puntuacion);
  } else {
    console.log("Estructura de datos no esperada:", JSON.stringify(inputData));
  }
} catch (error) {
  console.log("Error obteniendo datos del AI Agent:", error);
}

// Si la puntuación no está definida, intentar asignarle un valor por defecto
if (!puntuacion) {
  puntuacion = "7"; // Valor por defecto si no se encuentra
  console.log("Usando valor de puntuación por defecto:", puntuacion);
}

// Obtener nombre del asesor
let nombreAsesor = '';
try {
  const asesorNode = $('NombreAsesor');
  if (asesorNode && asesorNode.item && asesorNode.item.json) {
    nombreAsesor = asesorNode.item.json.NombreAsesor || '';
  }
} catch (error) {
  console.log("Error obteniendo nombre del asesor:", error);
}

// Obtener transcripción
let transcripcion = '';
try {
  const transcripcionNode = $('TRANSCRIPCION1');
  if (transcripcionNode && transcripcionNode.item && transcripcionNode.item.json) {
    transcripcion = transcripcionNode.item.json.transcript || '';
  }
} catch (error) {
  console.log("Error obteniendo transcripción:", error);
}

// Crear array de campos personalizados directamente como objetos JSON
let custom_fields = [];

// Agregar campos solo si tienen valor
if (nombreAsesor) {
  custom_fields.push({
    id: CUSTOM_FIELDS.asistente,
    value: sanitizarTexto(nombreAsesor)
  });
}

if (transcripcion) {
  custom_fields.push({
    id: CUSTOM_FIELDS.transcripcion,
    value: sanitizarTexto(transcripcion)
  });
}

if (preguntasRequeridas) {
  custom_fields.push({
    id: CUSTOM_FIELDS.preguntas_requeridas,
    value: sanitizarTexto(preguntasRequeridas)
  });
}

if (excesosIdentificados) {
  custom_fields.push({
    id: CUSTOM_FIELDS.excesos_identificados,
    value: sanitizarTexto(excesosIdentificados)
  });
}

if (evaluacionGeneral) {
  custom_fields.push({
    id: CUSTOM_FIELDS.evaluacion_general,
    value: sanitizarTexto(evaluacionGeneral)
  });
}

// Agregar dirección correcta si tiene valor
if (direccionCorrecta) {
  custom_fields.push({
    id: CUSTOM_FIELDS.direccion_correcta,
    value: sanitizarTexto(direccionCorrecta)
  });
}

// Intentamos la puntuación como texto corto (short_text)
if (puntuacion !== undefined && puntuacion !== null) {
  try {
    // Para un campo de tipo "short_text", debemos asegurarnos de que sea un string
    custom_fields.push({
      id: CUSTOM_FIELDS.puntuacion,
      value: String(puntuacion).trim()
    });

    console.log("Puntuación agregada como short_text:", String(puntuacion).trim());
  } catch (error) {
    console.log("Error procesando puntuación:", error);
  }
}

// Agregar areas de mejora si tiene valor
if (areasDeMejora) {
  custom_fields.push({
    id: CUSTOM_FIELDS.areas_de_mejora,
    value: sanitizarTexto(areasDeMejora)
  });
}

// Agregar puntos debiles si tiene valor
if (puntosDebiles) {
  custom_fields.push({
    id: CUSTOM_FIELDS.puntos_debiles,
    value: sanitizarTexto(puntosDebiles)
  });
}

// Crear la estructura exacta para ClickUp
const clickupPayload = {
  name: "Resumen de llamada Setter",
  description: "",
  list_id: "901110495702",
  custom_fields: custom_fields
};

// Mostrar para depuración
console.log("Payload para ClickUp:", JSON.stringify(clickupPayload));

// NO usar JSON.stringify o estructuras anidadas adicionales
return [clickupPayload];

// Se obtiene la lista de items de entrada
const items = $input.all();
const outputItems = items.map(item => {
  // Se asume que el nombre del archivo viene en item.json.nombre
  const fileName = item.json.nombre;

  // Expresión regular para extraer dígitos entre guiones bajos: _número_
  const regex = /_(\d+)_/;
  const match = fileName.match(regex);

  // Convertir duration de segundos a minutos con 2 decimales
  const durationInSeconds = item.json.duration || 0;
  const durationInMinutes = (durationInSeconds / 60).toFixed(2);

  if (!match) {
    // Si no se encuentra el patrón, se retorna un error en el item
    return { 
      json: { 
        error: `No se encontró el número en el nombre: ${fileName}`,
        durationInMinutes: durationInMinutes
      } 
    };
  }

  // El primer grupo capturado es el número
  const extractedNumber = match[1];

  // Mapeo de números a nombres según la tabla proporcionada
  const mapping = {
    "101": "Miguel Moreno",
    "250": "Cesar Hernandez",
    "290": "Dorvelis Pineda",
    "299": "IVR Menu 1",
    "300": "Setters",
    "301": "Ana Karina Kristen",
    "302": "Carlos Perez",
    "303": "Nora castillo",
    "304": "Lorraine Atencio",
    "308": "Yelitza castillo",
    "310": "Nordelys Rodriguiez",
    "350": "Carlen Gonzalez",
    "351": "Yonmar Gonzalez",
    "352": "Carolina Santana",
    "353": "Paola Medina",
    "355": "Francelis Sanchez",
    "356": "Juan Raúl Martínez",
    "391": "Ridchell Ladera",
    "399": "Patricia Medina",
    "401": "Andrea P",
    "402": "David F",
    "403": "Diego Delgado",
    "450": "Leopoldo Aponte",
    "499": "Customer Experience",
    "501": "Glendy Aguil",
    "961": "genesis carbone"
  };

  // Se obtiene el nombre correspondiente al número extraído. 
  // Si no se encuentra, se asigna "Nombre no encontrado".
  const nombreCorrespondiente = mapping[extractedNumber] || "Nombre no encontrado";

  // Se retorna el item con el resultado deseado y la duración en minutos
  return { 
    json: { 
      fileName,
      extractedNumber,
      nombreCorrespondiente,
      durationInMinutes: durationInMinutes
    } 
  };
});
// Se retorna el array de items resultantes
return outputItems;
